import "./styles.css";
import { BrowserRouter, Routes, Route } from "react-router-dom";


import Buttons from "./Buttons";
import IssueCardDemo from "./Issue-Card";
import CompareCardDemo from "./Compare-Card";


function Navigation() {
  return(
  <div class="mb-4 flex items-center">
    <a class="flex h-7 items-center justify-center rounded-full px-4 text-center text-sm transition-colors hover:text-primary bg-muted font-medium text-primary" href="/buttons">Mail</a>
    <a class="flex h-7 items-center justify-center rounded-full px-4 text-center text-sm transition-colors hover:text-primary text-muted-foreground" href="/issues">Dashboard</a>

  </div>
)}

export default function App() {
  return (
    <div>
      <Routes>
          <Route path="/" element={<Navigation /> }>
            <Route path="buttons" element={<Buttons />} />
            <Route path="issues" element={<IssueCardDemo />} />
            <Route path="compare" element={<CompareCardDemo />} />
            <Route path="*" element={<div>No Page</div>} />
          </Route>
      </Routes>

    </div>
  );
}
